// Calculate yesterday's date range
const now = new Date();
const yesterday = new Date(now);
yesterday.setDate(yesterday.getDate() - 1);

const startOfDay = new Date(yesterday.setHours(0, 0, 0, 0));
const endOfDay = new Date(yesterday.setHours(23, 59, 59, 999));

return {
  date: yesterday.toISOString().split('T')[0],
  start_timestamp: startOfDay.toISOString(),
  end_timestamp: endOfDay.toISOString()
};

// Aggregate all cost data
const dateInfo = $node['get_date_range'].json;
const executions = $node['query_workflow_executions'].json || [];
const apiUsage = $node['query_api_usage'].json || [];
const storageRaw = $node['query_storage_usage'].json?.stdout || '';
const dockerStats = $node['get_docker_stats'].json?.stdout || '';

// Parse storage usage
const storageLines = storageRaw.split('\n').filter(l => l.trim());
let totalStorageBytes = 0;
const dbSizes = {};
storageLines.forEach(line => {
  const parts = line.trim().split('|');
  if (parts.length >= 2) {
    const dbName = parts[0].trim();
    const size = parseInt(parts[1].trim());
    if (!isNaN(size)) {
      dbSizes[dbName] = size;
      totalStorageBytes += size;
    }
  }
});

// Calculate API costs
let totalApiCost = 0;
const apiCostsByService = {};
apiUsage.forEach(usage => {
  const cost = parseFloat(usage.total_cost) || 0;
  totalApiCost += cost;
  if (!apiCostsByService[usage.service_name]) {
    apiCostsByService[usage.service_name] = 0;
  }
  apiCostsByService[usage.service_name] += cost;
});

// Estimate compute costs (simplified)
const executionCount = executions.reduce((sum, e) => sum + parseInt(e.execution_count), 0);
const avgExecutionMs = executions.reduce((sum, e) => sum + parseFloat(e.avg_duration), 0) / (executions.length || 1);
const estimatedComputeCost = (executionCount * avgExecutionMs / 1000 / 3600) * 0.01; // $0.01 per compute-hour estimate

// Estimate storage costs
const storageGB = totalStorageBytes / (1024 * 1024 * 1024);
const estimatedStorageCost = storageGB * 0.023; // $0.023 per GB/month, prorated

const totalEstimatedCost = totalApiCost + estimatedComputeCost + estimatedStorageCost;

return {
  date: dateInfo.date,
  workflow_stats: {
    total_executions: executionCount,
    avg_duration_ms: avgExecutionMs,
    executions_by_workflow: executions
  },
  api_costs: {
    total: totalApiCost,
    by_service: apiCostsByService,
    details: apiUsage
  },
  storage: {
    total_gb: storageGB.toFixed(2),
    estimated_cost: estimatedStorageCost.toFixed(4),
    databases: dbSizes
  },
  compute: {
    execution_count: executionCount,
    estimated_cost: estimatedComputeCost.toFixed(4)
  },
  summary: {
    total_estimated_cost: totalEstimatedCost.toFixed(4),
    api_cost: totalApiCost.toFixed(4),
    compute_cost: estimatedComputeCost.toFixed(4),
    storage_cost: estimatedStorageCost.toFixed(4)
  }
};

// Generate daily cost report
const data = $json;
const report = `Daily Cost Report - ${data.date}
===========================================

Total Estimated Cost: $${data.summary.total_estimated_cost}

Breakdown:
- API Costs: $${data.summary.api_cost}
- Compute Costs: $${data.summary.compute_cost}
- Storage Costs: $${data.summary.storage_cost}

Workflow Activity:
- Total Executions: ${data.workflow_stats.total_executions}
- Avg Duration: ${data.workflow_stats.avg_duration_ms.toFixed(0)}ms

Storage Usage: ${data.storage.total_gb} GB
`;

console.log(report);
return { report, ...data };
